# PACK035_QUIET_NEWS_CACHE_REFRESH
# ================================================================================
def _pack035_quiet_news_cache_refresh(symbols=None):
    """
    Safely run news cache refresh only if the refresh function exists.

    This prevents Tower route tests from getting spammed by:
    [NEWS_CACHE_AUTO_REFRESH] name 'refresh_news_for_symbols' is not defined
    """
    refresh_func = globals().get("refresh_news_for_symbols")
    if not callable(refresh_func):
        return {
            "ok": True,
            "status": "skipped",
            "reason_code": "news_refresh_function_missing",
            "human_reason": "News refresh function is not loaded in this runtime.",
        }

    try:
        if symbols is None:
            return refresh_func()
        return refresh_func(symbols)
    except TypeError:
        return refresh_func()
    except Exception as exc:
        return {
            "ok": False,
            "status": "failed_safely",
            "reason_code": "news_refresh_failed",
            "human_reason": f"{type(exc).__name__}: {exc}",
        }
app = Flask(__name__, template_folder="templates", static_folder="static")

# PACK 022E: Register The Tower routes after final Flask app assignment.
def _pack022e_register_tower_routes_once(_app):
    try:
        import sys as _sys
        import importlib as _importlib
        import importlib.util as _importlib_util
        from pathlib import Path as _Path

        _root = str(_Path(__file__).resolve().parents[1])
        if _root not in _sys.path:
            _sys.path.insert(0, _root)

        _existing = {str(_rule.rule) for _rule in _app.url_map.iter_rules()}
        if "/tower/security-command" in _existing:
            print("PACK 022E: The Tower web routes already registered.")
            return True

        try:
            _bridge = _importlib.import_module("tower.web_bridge")
        except Exception as _import_error:
            _bridge_path = _Path(_root) / "tower" / "web_bridge.py"
            if not _bridge_path.exists():
                raise _import_error

            _spec = _importlib_util.spec_from_file_location("tower_web_bridge_pack022e", str(_bridge_path))
            if _spec is None or _spec.loader is None:
                raise _import_error

            _bridge = _importlib_util.module_from_spec(_spec)
            _spec.loader.exec_module(_bridge)

        _bridge.register_tower_web_routes(_app)

        _routes = sorted(str(_rule.rule) for _rule in _app.url_map.iter_rules() if str(_rule.rule).startswith("/tower"))
        print("PACK 022E: The Tower web routes registered:", _routes)
        return True

    except Exception as exc:
        print("PACK 022E: The Tower web routes failed:", type(exc).__name__, str(exc))
        return False

_pack022e_register_tower_routes_once(app)

app.secret_key = "simpleemrktrade-dev-key-change-later"

# SECTION 13G — AUTOMATIC market_universe HOOK

from datetime import datetime, timedelta

_AUTO_REFRESH_STATE = {
    "last_attempt_at": None,
    "last_success_at": None,
    "last_error": "",
}


def ensure_market_universe_ready(force: bool = False, max_age_hours: int = 12, min_retry_seconds: int = 300):
    """
    Keeps market_universe wired in automatically without refreshing constantly.
    - refreshes if missing
    - refreshes if stale
    - throttles repeated retries after failures
    """
    global _AUTO_REFRESH_STATE

    now = datetime.now()
    last_attempt_at = _AUTO_REFRESH_STATE.get("last_attempt_at")

    if not force and last_attempt_at:
        if now - last_attempt_at < timedelta(seconds=min_retry_seconds):
            return {
                "ok": bool(_AUTO_REFRESH_STATE.get("last_success_at")),
                "skipped": True,
                "reason": "retry_throttled",
                "state": dict(_AUTO_REFRESH_STATE),
            }

    _AUTO_REFRESH_STATE["last_attempt_at"] = now
    summary_before = {}

    try:
        summary_before = market_universe.get_market_universe_summary() or {}
    except Exception:
        summary_before = {}

    total_before = int(summary_before.get("total", 0) or 0)

    try:
        needs_refresh = force or total_before == 0 or market_universe.market_universe_is_stale(max_age_hours=max_age_hours)

        if needs_refresh:
            rows = market_universe.refresh_market_universe()
            _AUTO_REFRESH_STATE["last_success_at"] = datetime.now().isoformat()
            _AUTO_REFRESH_STATE["last_error"] = ""
            return {
                "ok": True,
                "refreshed": True,
                "row_count": len(rows) if isinstance(rows, list) else 0,
                "state": dict(_AUTO_REFRESH_STATE),
            }

        rows = market_universe.load_market_universe()
        _AUTO_REFRESH_STATE["last_success_at"] = datetime.now().isoformat()
        _AUTO_REFRESH_STATE["last_error"] = ""
        return {
            "ok": True,
            "refreshed": False,
            "row_count": len(rows) if isinstance(rows, list) else 0,
            "state": dict(_AUTO_REFRESH_STATE),
        }

    except Exception as e:
        _AUTO_REFRESH_STATE["last_error"] = str(e)
        return {
            "ok": False,
            "refreshed": False,
            "error": str(e),
            "state": dict(_AUTO_REFRESH_STATE),
        }


@app.before_request
def auto_refresh_market_universe():
    try:
        refresh_market_universe_if_stale(max_age_hours=12)
    except Exception as e:
        print(f"[MARKET_UNIVERSE_AUTO_REFRESH] {e}")


@app.before_request
def auto_refresh_news_cache():
    try:
        pipeline = get_pipeline_status()
        freshness = _freshness_bucket(pipeline.get("news_sync_at"), stale_after_minutes=180)

        if freshness.get("is_stale"):
            universe = load_market_universe()
            if universe:
                refresh_news_for_symbols(
                    symbol_rows=universe,
                    limit_per_symbol=6,
                    max_symbols=250,
                    force=False,
                )
    except Exception as e:
        pass  # PACK035B: quiet missing/failed news refresh during Tower route tests


